queries.mysql:
SELECT su.userID, su.UserName, href.GuideId, g.Title, g.GuideType, sc.raw, href.mastery_score, core.lesson_status, core.Started, core.LastTime
FROM lmshref AS href
JOIN lmsusergroup AS ug ON ug.GroupId = {{groupId}}
JOIN smartassuser AS su ON su.UserID = ug.UserId
LEFT JOIN lmscmi AS cmi ON cmi.hRefId = href.hRefId AND cmi.UserId = ug.UserId AND cmi.CourseId = href.CourseID
LEFT JOIN lmscorescore AS sc ON sc.cmiId = cmi.cmiId
LEFT JOIN lmscore AS core ON core.cmiId = cmi.cmiId
LEFT JOIN guide AS g ON g.GuideID = href.GuideId
WHERE href.CourseID = {{courseId}}
ORDER BY su.UserName, href.hRefId;

queries.mssql:
SELECT su.userID, su.UserName, href.GuideId, g.Title, g.GuideType, sc.raw, href.mastery_score, core.lesson_status, core.Started, core.LastTime
FROM lmshref AS href
JOIN lmsusergroup AS ug ON ug.GroupId = {{groupId}}
JOIN smartassuser AS su ON su.UserID = ug.UserId
LEFT JOIN lmscmi AS cmi ON cmi.hRefId = href.hRefId AND cmi.UserId = ug.UserId AND cmi.CourseId = href.CourseID
LEFT JOIN lmscorescore AS sc ON sc.cmiId = cmi.cmiId
LEFT JOIN lmscore AS core ON core.cmiId = cmi.cmiId
LEFT JOIN guide AS g ON g.GuideID = href.GuideId
WHERE href.CourseID = {{courseId}}
ORDER BY su.UserName, href.hRefId;

